-- 2) Move misplaced sub-domains from Domain I to II and III

UPDATE performance_sub_domains sd
SET domain_id = d2.id
FROM performance_domains d1, performance_domains d2
WHERE sd.domain_id = d1.id AND d1.code = 'I' AND d2.code = 'II'
  AND sd.code IN ('2.1', '2.2');

UPDATE performance_sub_domains sd
SET domain_id = d3.id
FROM performance_domains d1, performance_domains d3
WHERE sd.domain_id = d1.id AND d1.code = 'I' AND d3.code = 'III'
  AND sd.code ~ '^3\.';



-- 3) Upsert sub-domains

INSERT INTO performance_sub_domains (id, domain_id, code, name_kh, name_en, sort_order)
SELECT gen_random_uuid(), dom.id, '1.1', '1.1 бһҖбһ¶бһҡбһӣбһҫбһҖбһҖбһҳбҹ’бһ–бһҹбҹӢбһӣбһ‘бҹ’бһ’бһ·бһ”бҹ’бһҡбһҮбһ¶бһ’бһ·бһ”бһҸбҹҒбһҷбҹ’бһҷбһ“бҹ…бһҳбһјбһӣбһҠбҹ’бһӢбһ¶бһ“', '1.1 бһҖбһ¶бһҡбһӣбһҫбһҖбһҖбһҳбҹ’бһ–бһҹбҹӢбһӣбһ‘бҹ’бһ’бһ·бһ”бҹ’бһҡбһҮбһ¶бһ’бһ·бһ”бһҸбҹҒбһҷбҹ’бһҷбһ“бҹ…бһҳбһјбһӣбһҠбҹ’бһӢбһ¶бһ“', 1
FROM performance_domains dom WHERE dom.code = 'I'
