WHERE sd.code = '1.1'
ON CONFLICT (sub_domain_id, code) DO UPDATE SET
  name_kh = EXCLUDED.name_kh,
  data_type = EXCLUDED.data_type,
  unit_kh = EXCLUDED.unit_kh,
  unit_en = EXCLUDED.unit_en,
  sort_order = EXCLUDED.sort_order;

INSERT INTO performance_indicators (id, sub_domain_id, code, name_kh, name_en, data_type, unit_kh, unit_en, sort_order)
SELECT gen_random_uuid(), sd.id, v.code, v.name_kh, v.name_en, v.data_type::indicator_data_type, v.unit_kh, v.unit_en, v.sort_order
FROM performance_sub_domains sd
JOIN performance_domains dom ON dom.id = sd.domain_id AND dom.code = 'I'
CROSS JOIN (VALUES
  ('1', 'бһ…бҹҶбһ“бһҪбһ“бһҖбһҡбһҺбһёбһҡбҹҶбһӣбҹ„бһ—бһҹбһ·бһ‘бҹ’бһ’бһ·бһҳбһ“бһ»бһҹбҹ’бһҹбһ–бһ¶бһҖбҹӢбһ–бҹҗбһ“бҹ’бһ’бһ“бһ№бһ„бһҖбһ¶бһҡбһ”бҹ’бһҡбһҖбһ¶бһ“бҹӢбһ–бһјбһҮбһҹбһ¶бһҹбһ“бҹҚ бһ–бһҺбҹҢбһҹбһҳбҹ’бһ”бһ»бһҡ бһ—бҹҒбһ‘ бһ—бһ¶бһҹбһ¶ бһҮбҹҶбһ“бһҝбһҹбһ¶бһҹбһ“бһ¶ бһ“бһ·бһ“бҹ’бһ“бһ¶бһҖбһ¶бһҡбһ“бһҷбҹ„бһ”бһ¶бһҷ бһўбһҸбһёбһҸбһҖбһ¶бһӣ бһҠбһҫбһҳбһҖбҹҶбһҺбһҫбһҸбһҮбһ¶бһҸбһ· бһӢбһ¶бһ“бҹҲбһҹбһ„бҹ’бһӮбһҳ бһ’бһ“бһ’бһ¶бһ“ бһ¬бһҹбҹ’бһҗбһ¶бһ“бһ—бһ¶бһ–бһҜбһ‘бҹҖбһҸ', NULL, 'number', 'бһҖбһҡбһҺбһё', 'cases', 1),
  ('2', 'бһ…бҹҶбһ“бһҪбһ“бһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһҠбҹӮбһӣбһ”бһ¶бһ“бһ…бһјбһӣбһҡбһҪбһҳбһңбҹҒбһ‘бһ·бһҖбһ¶бһҹбһ¶бһ’бһ¶бһҡбһҺбҹҲбһҡбһ”бһҹбҹӢбһғбһ»бҹҶ бһҹбһ„бҹ’бһҖбһ¶бһҸбҹӢ', NULL, 'number', 'бһ“бһ¶бһҖбҹӢ', 'people', 2),
  ('3', 'бһ…бҹҶбһ“бһҪбһ“бһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһҠбҹӮбһӣбһ”бһ¶бһ“бһ…бһјбһӣбһҡбһҪбһҳбһҖбһ·бһ…бҹ’бһ…бһ”бҹ’бһҡбһҮбһ»бҹҶбһҖбҹ’бһҡбһ»бһҳбһ”бҹ’бһҡбһ№бһҖбҹ’бһҹбһ¶бһғбһ»бҹҶ бһҹбһ„бҹ’бһҖбһ¶бһҸбҹӢ', NULL, 'number', 'бһ“бһ¶бһҖбҹӢ', 'people', 3),
  ('4', 'бһ…бҹҶбһ“бһҪбһ“бһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһ…бһјбһӣбһҡбһҪбһҳбһҖбҹ’бһ“бһ»бһ„бһҠбҹҶбһҺбһҫбһҡбһҖбһ¶бһҡбһҡбҹҖбһ”бһ…бҹҶбһ•бҹӮбһ“бһҖбһ¶бһҡбһўбһ—бһ·бһңбһҢбҹ’бһҚ бһ“бһ·бһ„бһҖбһҳбҹ’бһҳбһңбһ·бһ’бһёбһңбһ·бһ“бһ·бһҷбҹ„бһӮбҹЈбһҶбҹ’бһ“бһ¶бҹҶбһҡбҹҶбһҖбһ·бһӣбһҡбһ”бһҹбҹӢбһғбһ»бҹҶ бһҹбһ„бҹ’бһҖбһ¶бһҸбҹӢ', NULL, 'number', 'бһ“бһ¶бһҖбҹӢ', 'people', 4),
  ('5', 'бһғбһ»бҹҶ бһҹбһ„бҹ’бһҖбһ¶бһҸбҹӢбһҠбҹӮбһӣбһ”бһ¶бһ“бһ”бһ„бҹ’бһҖбһҫбһҸбһӮбһҺбһҖбһҳбҹ’бһҳбһҖбһ¶бһҡбһӮбҹ’бһҡбһ”бҹӢбһӮбҹ’бһҡбһ„бһӮбһҳбҹ’бһҡбҹ„бһ„бһҠбҹӮбһӣбһҳбһ¶бһ“бһҖбһ¶бһҡбһ…бһјбһӣбһҡбһҪбһҳбһ–бһёбһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢ', NULL, 'binary', 'бһҳбһ¶бһ“ / бһҳбһ·бһ“бһҳбһ¶бһ“', 'Yes / No', 5),
  ('6', 'бһ…бҹҶбһ“бһҪбһ“бһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһҠбҹӮбһӣбһ”бһ¶бһ“бһ‘бһ‘бһҪбһӣбһҹбҹҒбһңбһ¶бһҡбһҠбҹ’бһӢбһ”бһ¶бһӣбһғбһ»бҹҶ бһҹбһ„бҹ’бһҖбһ¶бһҸбҹӢ', NULL, 'number', 'бһ“бһ¶бһҖбҹӢ', 'people', 6),
  ('7', 'бһ…бҹҶбһ“бһҪбһ“бһӮбһҳбҹ’бһҡбҹ„бһ„ (бһҹбҹҒбһңбһ¶бһҹбһ„бҹ’бһӮбһҳ бһ“бһ·бһ„бһ бҹҒбһҠбҹ’бһӢбһ¶бһҡбһ…бһ“бһ¶бһҹбһҳбҹ’бһ–бҹҗбһ“бҹ’бһ’) бһҠбҹӮбһӣбһ”бһ¶бһ“бһҡбҹҖбһ”бһ…бҹҶ бһ“бһ·бһ„бһўбһ“бһ»бһңбһҸбҹ’бһҸбһҠбҹ„бһҷбһғбһ»бҹҶ бһҹбһ„бҹ’бһҖбһ¶бһҸбҹӢ', NULL, 'number', 'бһӮбһҳбҹ’бһҡбҹ„бһ„', 'projects', 7),
  ('8', 'бһҹбҹҶбһҺбһҫ бһҹбҹҶбһҺбһјбһҳбһ–бһҡ бһҖбҹ’бһҸбһёбһҖбһ„бҹ’бһңбһӣбҹӢ бһ“бһ·бһ„бһ”бһүбҹ’бһ бһ¶бһ”бҹ’бһҡбһҲбһҳбһ“бһ¶бһ“бһ¶бһҡбһ”бһҹбҹӢбһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһ–бһ¶бһҖбҹӢбһ–бҹҗбһ“бҹ’бһ’бһ“бһ№бһ„бһҖбһ¶бһҡбһ•бҹ’бһҸбһӣбҹӢбһҹбҹҒбһңбһ¶', NULL, 'number', 'бһҖбһҡбһҺбһё', 'cases', 8),
  ('9', 'бһҖбһ¶бһҡбһҹбһҳбҹ’бһҡбһ»бҹҮбһҹбһҳбҹ’бһҡбһҪбһӣбһҠбҹ„бҹҮбһҹбҹ’бһҡбһ¶бһҷбһҹбҹҶбһҺбһҫ бһҹбҹҶбһҺбһјбһҳбһ–бһҡ бһҖбҹ’бһҸбһёбһҖбһ„бҹ’бһңбһӣбҹӢ бһ“бһ·бһ„бһ”бһүбҹ’бһ бһ¶бһ”бҹ’бһҡбһҲбһҳбһ“бһ¶бһ“бһ¶', NULL, 'number', 'бһҖбһҡбһҺбһё', 'cases', 9)
) AS v(code, name_kh, name_en, data_type, unit_kh, unit_en, sort_order)
