INSERT INTO performance_indicators (id, sub_domain_id, code, name_kh, name_en, data_type, unit_kh, unit_en, sort_order)
SELECT gen_random_uuid(), sd.id, v.code, v.name_kh, v.name_en, v.data_type::indicator_data_type, v.unit_kh, v.unit_en, v.sort_order
FROM performance_sub_domains sd
JOIN performance_domains dom ON dom.id = sd.domain_id AND dom.code = 'I'
CROSS JOIN (VALUES
  ('1', 'бһңбһ·бһңбһ¶бһ‘бһ–бһ¶бһҖбҹӢбһ–бҹҗбһ“бҹ’бһ’бһ“бһ№бһ„бһҮбҹҶбһ“бһҝ бһ”бҹ’бһҡбһ–бҹғбһҺбһё бһ“бһ·бһ„бһҹбһ¶бһҹбһ“бһ¶бһ•бҹ’бһҹбҹҒбһ„бҹ—бһӮбҹ’бһ“бһ¶бһ“бҹ…бһҳбһјбһӣбһҠбҹ’бһӢбһ¶бһ“', NULL, 'number', 'бһҖбһҡбһҺбһё', 'cases', 1),
  ('2', 'бһҖбһҡбһёбһҺбһңбһ·бһңбһ¶бһ‘бһҡбһңбһ¶бһ„бһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһ“бһ·бһ„бһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһ–бһ¶бһҖбҹӢбһ–бҹҗбһ“бҹ’бһ’бһ“бһ№бһ„бһ“бһ·бһ“бҹ’бһ“бһ¶бһҖбһ¶бһҡ бһ“бһҷбҹ„бһ”бһ¶бһҷ', NULL, 'number', 'бһҖбһҡбһҺбһё', 'cases', 2),
  ('3', 'бһғбһ»бҹҶ бһҹбһ„бҹ’бһҖбһ¶бһҸбҹӢбһҠбҹӮбһӣбһҳбһ¶бһ“бһҳбһҺбҹ’бһҢбһӣ бһ‘бһёбһ’бҹ’бһӣбһ¶бһҹбһ¶бһ’бһ¶бһҡбһҺбҹҲ бһ¬бһўбһӮбһ¶бһҡбһңбһ”бҹ’бһ”бһ’бһҳбҹҢбһҖбҹ’бһ“бһ»бһ„бһҹбһ бһӮбһҳбһ“бҹҚбһҠбҹӮбһӣбһҹбһ¶бһ’бһ¶бһҡбһҺбһҮбһ“бһўбһ¶бһ…бһҳбһ¶бһ“бһҖбһ¶бһҡбһҮбһҪбһ”бһҮбһ»бҹҶ бһҖбһ¶бһҡбһҹбһҳбҹ’бһҸбҹӮбһ„ бһ“бһ·бһ„бһҖбһ¶бһҡбһ…бҹӮбһҖбһҡбҹҶбһӣбҹӮбһҖбһ“бһјбһңбһҹбһ·бһӣбҹ’бһ”бҹҲ бһ”бҹ’бһҡбһ–бҹғбһҺбһё бһ‘бҹҶбһ“бҹҖбһҳбһ‘бһҳбҹ’бһӣбһ¶бһ”бҹӢ бһҹбһ¶бһҹбһ“бһ¶ бһ“бһ·бһ„бһ…бҹҶбһҺбҹҒбҹҮбһҠбһ№бһ„бһ•бҹ’бһҹбҹҒбһ„бҹ—', NULL, 'binary', 'бһҳбһ¶бһ“ / бһҳбһ·бһ“бһҳбһ¶бһ“', 'Yes / No', 3)
) AS v(code, name_kh, name_en, data_type, unit_kh, unit_en, sort_order)
WHERE sd.code = '1.3'
ON CONFLICT (sub_domain_id, code) DO UPDATE SET
  name_kh = EXCLUDED.name_kh,
  data_type = EXCLUDED.data_type,
  unit_kh = EXCLUDED.unit_kh,
  unit_en = EXCLUDED.unit_en,
