  ('2', 'бһҹбһҳбһ¶бһҮбһ·бһҖбһҖбҹ’бһҡбһ»бһҳбһ”бҹ’бһҡбһ№бһҖбҹ’бһҹбһ¶бһҖбҹ’бһҡбһ»бһ„ бһҹбҹ’бһҡбһ»бһҖ бһҒбһҺбҹ’бһҢбһҮбһ¶бһҹбһҳбһ¶бһҮбһ·бһҖбһӮбһҺбҹҲбһҖбһҳбҹ’бһҳбһ¶бһ’бһ·бһҖбһ¶бһҡбһӮбҹ’бһҡбһ”бҹӢбһӮбҹ’бһҡбһ„бһҹбһ¶бһӣбһ¶бһҡбҹҖбһ“', NULL, 'binary', 'бһҳбһ¶бһ“ / бһҳбһ·бһ“бһҳбһ¶бһ“', 'Yes / No', 2),
  ('3', 'бһ…бҹҶбһ“бһҪбһ“бһҖбһ·бһ…бҹ’бһ…бһ”бҹ’бһҡбһҮбһ»бҹҶбһ”бҹ’бһҡбһ…бһ¶бҹҶбһҒбҹӮбһҡбһ”бһҹбҹӢбһӮбһҺбҹҲбһҖбһҳбҹ’бһҳбһҖбһ¶бһҡбһӮбҹ’бһҡбһ”бҹӢбһӮбҹ’бһҡбһ„бһҹбһ¶бһӣбһ¶бһҡбҹҖбһ“', NULL, 'number', 'бһҠбһ„', 'times', 3),
  ('4', 'бһӮбҹ’бһҡбһјбһ”бһ„бҹ’бһҡбҹҖбһ“бһ“бҹ…бһҸбһ¶бһҳбһҸбҹҶбһ”бһ“бҹӢбһҠбһ¶бһ…бҹӢбһҹбҹ’бһҡбһҷбһ¶бһӣ бһ“бһ·бһ„бһҸбҹҶбһ”бһ“бҹӢбһҮбһҪбһ”бһҖбһ¶бһҡбһӣбҹҶбһ”бһ¶бһҖ бһҸбҹ’бһҡбһјбһңбһ”бһ¶бһ“бһӮбһ¶бҹҶбһ‘бҹ’бһҡ бһ“бһ·бһ„бһӣбһҫбһҖбһ‘бһ№бһҖбһ…бһ·бһҸбҹ’бһҸ (бһҳбһ¶бһ“ бһ¬бһӮбҹ’бһҳбһ¶бһ“) бһҠбҹӮбһҡбһ¬бһ‘бҹҒ?', NULL, 'binary', 'бһҳбһ¶бһ“ / бһҳбһ·бһ“бһҳбһ¶бһ“', 'Yes / No', 4),
  ('5', 'бһ”бһҫбһҳбһ¶бһ“бһҹбһјбһҳбһҡбҹҖбһ”бһҡбһ¶бһ”бҹӢбһҖбһ¶бһҡбһӮбһ¶бҹҶбһ‘бҹ’бһҡбһӮбҹ’бһҡбһјбһ”бһ„бҹ’бһҡбҹҖбһ“бһ“бҹ…бһҸбһ¶бһҳбһҸбҹҶбһ”бһ“бҹӢбһҠбһ¶бһ…бҹӢбһҹбҹ’бһҡбһҷбһ¶бһӣ бһ“бһ·бһ„бһҸбҹҶбһ”бһ“бҹӢбһҮбһҪбһ”бһҖбһ¶бһҡбһӣбҹҶбһ”бһ¶бһҖ бһ‘бһ¶бҹҶбһ„бһ“бҹ„бҹҮ', NULL, 'binary', 'бһҳбһ¶бһ“ / бһҳбһ·бһ“бһҳбһ¶бһ“', 'Yes / No', 5),
  ('6', 'бһ…бҹҶбһ“бһҪбһ“бһ—бһ¶бһӮбһҡбһҷбһҹбһ·бһҹбҹ’бһҹбһҖбҹ’бһҡбһёбһҖбҹ’бһҡ бһҹбһ·бһҹбҹ’бһҹбһҹбҹ’бһҗбһ·бһҸбһҖбҹ’бһ“бһ»бһ„бһҸбҹҶбһ”бһ“бҹӢбһҮбһҪбһ”бһҖбһ¶бһҡбһӣбҹҶбһ”бһ¶бһҖ бһ“бһ·бһ„бһҹбһ·бһҹбҹ’бһҹбһҳбһ¶бһ“бһ–бһ·бһҖбһ¶бһҡбһ—бһ¶бһ–бһ‘бһ‘бһҪбһӣбһ”бһ¶бһ“бһўбһ¶бһ бһ¶бһҡбһјбһ”бһҖбһҡбһҺбҹҚ', NULL, 'percentage', 'бһ—бһ¶бһӮбһҡбһҷ(%)', '%', 6)
) AS v(code, name_kh, name_en, data_type, unit_kh, unit_en, sort_order)
WHERE sd.code = '3.2'
ON CONFLICT (sub_domain_id, code) DO UPDATE SET
