JOIN performance_domains dom ON dom.id = sd.domain_id AND dom.code = 'III'
CROSS JOIN (VALUES
  ('1', 'бҹЎ.вҖӢ бһ…бҹҶбһ“бһҪбһ“бһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһ‘бһ‘бһҪбһӣбһ”бһ¶бһ“бһҹбҹҒбһңбһ¶бһҗбҹӮбһ‘бһ¶бҹҶбһҹбһ»бһҒбһ—бһ¶бһ–бһ”бһӢбһҳбһ“бҹ…бһҳбһҺбҹ’бһҢбһӣбһҹбһ»бһҒбһ—бһ¶бһ–', NULL, 'number', 'бһ“бһ¶бһҖбҹӢ', 'people', 1),
  ('2', 'бһҳбһҺбҹ’бһҢбһӣбһҹбһ»бһҒбһ—бһ¶бһ–бһ“бҹ…бһғбһ»бҹҶ бһҹбһ„бҹ’бһҖбһ¶бһҸбҹӢ', NULL, 'binary', 'бһҳбһ¶бһ“ / бһҳбһ·бһ“бһҳбһ¶бһ“', 'Yes / No', 2),
  ('3', 'бһҳбһ“бҹ’бһ‘бһёбһҡбһ–бҹҒбһ‘бҹ’бһҷбһ”бһ„бҹ’бһўбҹӮбһҖбһ“бҹ…бһҖбҹ’бһ“бһ»бһ„бһҖбҹ’бһҡбһ»бһ„ бһҹбҹ’бһҡбһ»бһҖ бһҒбһҺбҹ’бһҢ', NULL, 'binary', 'бһҳбһ¶бһ“ / бһҳбһ·бһ“бһҳбһ¶бһ“', 'Yes / No', 3),
  ('4', 'бһҖбһ¶бһҡбһӣбһҫбһҖбһ‘бһ№бһҖбһ…бһ·бһҸбҹ’бһҸбһҠбһӣбҹӢбһӮбҹ’бһҡбһјбһ–бҹҒбһ‘бҹ’бһҷбһҠбҹӮбһӣбһ‘бҹ…бһ”бҹҶбһ–бҹҒбһүбһҖбһ¶бһҡбһ„бһ¶бһҡбһ“бҹ…бһҸбҹҶбһ”бһ“бҹӢбһҮбһ“бһ”бһ‘ бһҸбҹҶбһ”бһ“бҹӢбһҠбһ¶бһ…бҹӢбһҹбҹ’бһҡбһҷбһ¶бһӣ бһ“бһ·бһ„бһҸбҹҶбһ”бһ“бҹӢбһҮбһҪбһ”бһҖбһ¶бһҡбһӣбҹҶбһ”бһ¶бһҖ бһҸбһ¶бһҳбһҡбһҷбҹҲбһҖбһ¶бһҡбһ•бҹ’бһҸбһӣбҹӢбһ”бҹ’бһҡбһ¶бһҖбҹӢбһ§бһ”бһҸбҹ’бһҗбһҳбҹ’бһ—бһ”бһ“бҹ’бһҗбҹӮбһҳ бһ¬', NULL, 'binary', 'бһҳбһ¶бһ“ / бһҳбһ·бһ“бһҳбһ¶бһ“', 'Yes / No', 4),
  ('5', 'бһҳбһ¶бһ“бһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһ…бһјбһӣбһҡбһҪбһҳбһҖбҹ’бһ“бһ»бһ„бһӮбһҺбҹҲбһҖбһҳбҹ’бһҳбһҖбһ¶бһҡбһӮбҹ’бһҡбһ”бҹӢбһӮбҹ’бһҡбһ„бһҳбһҺбҹ’бһҢбһӣбһҹбһ»бһҒбһ—бһ¶бһ– бһ“бһ·бһ„бһҖбҹ’бһҡбһ»бһҳбһ‘бҹ’бһҡбһ‘бҹ’бһҡбһ„бҹӢбһҹбһ»бһҒбһ—бһ¶бһ–бһ—бһјбһҳбһ· бһўбҹ’бһ“бһҖбһҹбҹ’бһҳбҹҗбһӮбҹ’бһҡбһ…бһ·бһҸбҹ’бһҸбһ”бһҳбҹ’бһҡбһҫбһҖбһ¶бһҡбһ„бһ¶бһҡбһҹбһ»бһҒбһ—бһ¶бһ–бһҸбһ¶бһҳбһҹбһ бһӮбһҳбһ“бҹҚ', NULL, 'binary', 'бһҳбһ¶бһ“ / бһҳбһ·бһ“бһҳбһ¶бһ“', 'Yes / No', 5),
  ('6', 'бһғбһ»бҹҶ бһҹбһ„бҹ’бһҖбһ¶бһҸбҹӢбһҳбһ¶бһ“бһ‘бһёбһҖбһ“бҹ’бһӣбҹӮбһ„бһ бһ¶бһҸбҹӢбһ”бҹ’бһҡбһ¶бһҺ бһ¬бһ бһ¶бһҸбҹӢбһҖбһёбһЎбһ¶бһҹбһ¶бһ’бһ¶бһҡбһҺбҹҲ', NULL, 'binary', 'бһҳбһ¶бһ“ / бһҳбһ·бһ“бһҳбһ¶бһ“', 'Yes / No', 6),
  ('7', 'бһ…бҹҶбһ“бһҪбһ“бһҖбһҳбҹ’бһҳбһңбһ·бһ’бһё бһҖбһ·бһ…бҹ’бһ…бһ”бҹ’бһҡбһҮбһ»бҹҶ бһ¬бһ–бҹ’бһҡбһ№бһҸбҹ’бһҸбһҖбһ¶бһҡбһҺбҹҚбһ•бҹ’бһҹбһ–бҹ’бһңбһ•бҹ’бһҹбһ¶бһҷбһҖбһ¶бһҡбһҷбһӣбҹӢбһҠбһ№бһ„бһҡбһ”бһҹбҹӢбһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһҖбҹ’бһ“бһ»бһ„бһҖбһ¶бһҡбһңбһ·бһ’бһ¶бһ“бһҹбһ»бһҒбһ¶бһ—бһ·бһ”бһ¶бһӣ бһҠбһҫбһҳбҹ’бһ”бһёбһ”бһ„бҹ’бһҖбһ¶бһҡ бһ“бһ·бһ„бһ‘бһ”бҹӢбһҹбҹ’бһҖбһ¶бһҸбҹӢбһҖбһ¶бһҡбһҶбҹ’бһӣбһ„бһҡбһ¶бһӣбһҠбһ¶бһӣбһҮбҹҶбһ„бһәбһҖбһјбһңбһёбһҠбҹЎбҹ© бһ“бһ·бһ„бһҖбһ¶бһҸбҹӢбһ”бһ“бҹ’бһҗбһҷбһҖбһ¶бһҡбһ”бҹ’бһҡбһҲбһҳбһ“бһ№бһ„бһҖбһҸбҹ’бһҸбһ¶бһ бһ¶бһ“бһ·бһ—бҹҗбһҷбһ“бҹғбһҮбҹҶбһ„бһәбһҳбһ·бһ“бһҶбҹ’бһӣбһ„ бһҠбҹӮбһӣбһ”бһ¶бһ“бһҡбҹҖбһ”бһ…бҹҶ', NULL, 'number', 'бһҠбһ„', 'times', 7),
  ('8', 'бһ…бҹҶбһ“бһҪбһ“бһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһ…бһјбһӣбһҡбһҪбһҳбһҖбһҳбҹ’бһҳбһңбһ·бһ’бһё бһҖбһ·бһ…бҹ’бһ…бһ”бҹ’бһҡбһҮбһ»бҹҶ бһ¬бһ–бҹ’бһҡбһ№бһҸбҹ’бһҸбһҖбһ¶бһҡбһҺбҹҚбһ•бҹ’бһҹбһ–бҹ’бһңбһ•бҹ’бһҹбһ¶бһҷбһҖбһ¶бһҡбһҷбһӣбҹӢбһҠбһ№бһ„бһҡбһ”бһҹбҹӢбһ”бҹ’бһҡбһҮбһ¶бһ–бһӣбһҡбһҠбҹ’бһӢбһҖбҹ’бһ“бһ»бһ„бһҖбһ¶бһҡбһңбһ·бһ’бһ¶бһ“бһҹбһ»бһҒбһ¶бһ—бһ·бһ”бһ¶бһӣ бһҠбһҫбһҳбҹ’бһ”бһёбһ”бһ„бҹ’бһҖбһ¶бһҡ бһ“бһ·бһ„бһ‘бһ”бҹӢбһҹбҹ’бһҖбһ¶бһҸбҹӢбһҖбһ¶бһҡбһҶбҹ’бһӣбһ„бһҡбһ¶бһӣбһҠбһ¶бһӣбһҮбҹҶбһ„бһәбһҖбһјбһңбһёбһҠбҹЎбҹ© бһ“бһ·бһ„бһҖбһ¶бһҸбҹӢбһ”бһ“бҹ’бһҗбһҷбһҖбһ¶бһҡбһ”бҹ’бһҡбһҲбһҳбһ“бһ№бһ„бһҖбһҸбҹ’бһҸбһ¶бһ бһ¶бһ“бһ·бһ—бҹҗбһҷбһ“бҹғбһҮбҹҶбһ„бһәбһҳбһ·бһ“бһҶбҹ’бһӣбһ„', NULL, 'number', 'бһ“бһ¶бһҖбҹӢ', 'people', 8)
) AS v(code, name_kh, name_en, data_type, unit_kh, unit_en, sort_order)
